import requests
import concurrent.futures

with open('/tmp/words.txt', 'r') as f:
    words = f.read().splitlines()

words += ["bot", "cmd", "command", "c", "urmom", "target", "id", "ip", "bot_id", "botid", "execute", "payload", "agent", "cc", "c2", "file", "upload", "submit", "data", "botnet", "command_id", "machine_id", "uuid", "mac_address", "user", "pass"]
words = list(set([w for w in words if w]))

def check(word):
    url = "http://target:8127/console"
    try:
        r = requests.get(f"{url}?{word}=1", timeout=3)
        if r.status_code != 400:
            print(f"GET param found: {word} -> {r.status_code}")
    except:
        pass
    try:
        r = requests.post(url, data={word: "1"}, timeout=3)
        if r.status_code != 400:
            print(f"POST param found: {word} -> {r.status_code}")
    except:
        pass
    try:
        r = requests.post(url, files={word: ('test.txt', '1')}, timeout=3)
        if r.status_code != 400:
            print(f"FILE param found: {word} -> {r.status_code}")
    except:
        pass

with concurrent.futures.ThreadPoolExecutor(max_workers=30) as executor:
    executor.map(check, words)
EOF

