import os
from uuid import getnode
print("node:", getnode())
def get_machine_id():
    rv = ""
    for filename in ["/etc/machine-id", "/var/lib/dbus/machine-id", "/sys/class/net/eth0/address"]:
        try:
            with open(filename, "rb") as f:
                rv += f.read().decode('utf-8').strip()
        except Exception:
            pass
    try:
        with open("/proc/sys/kernel/random/boot_id", "rb") as f:
            rv += f.read().decode('utf-8').strip()
    except Exception:
        pass
    try:
        with open("/proc/self/cgroup", "rb") as f:
            rv += f.read().decode('utf-8').split("0::/")[0].strip()
    except Exception:
        pass
    return rv
print("machine_id:", get_machine_id())
EOF

